import { Component, Host, h, Element, Prop, Method, Listen } from '@stencil/core';
import { Placement, CaretAlignment, PopOverSizes, PopoverDim } from './pop-over.model';
import {
  arrow,
  autoUpdate,
  computePosition,
  flip,
  offset,
  Side
} from '@floating-ui/dom';
import { isNullOrUndefined } from '@src/utils/mx-utils/utils';
import { AlignedPlacement } from '@floating-ui/utils';

@Component({
  tag: 'kds-popover',
  styleUrl: 'kds-popover.css'
})
export class KdsPopover {
  @Element() hostEle: HTMLKdsPopoverElement;

  /** Sets the placement of the popover(top/bottom/left/right) on the host element. */
  @Prop() readonly placement: Placement;
  /** Sets the alignment of the popover(center/left/right/top/bottom) on the host element. */
  @Prop() readonly alignment: CaretAlignment;
  /** Sets the size of the popover(small/large/medium). */
  @Prop() readonly size: PopOverSizes;
  /** Sets the container this element should be confined to. */
  @Prop() readonly appendTo: string | HTMLElement;
  /** Sets the zIndex of the Popover. */
  @Prop() readonly zIndex: string = '700';
  /** Sets the popover element id. */
  @Prop() readonly wrapperId: string;
  /** Sets whether the popover is closed when clicked outside the popover. */
  @Prop() readonly closeOnClickOutsidePopover: boolean = false;
  /** Sets whether the popover is closed when scroll outside the popover. */
  @Prop() readonly closeOnScrollOutsidePopover: boolean = false;

  private contentRef: HTMLKdsPopoverContentElement;
  private triggerRef: HTMLKdsPopoverWrapperElement;
  private arrowRef: HTMLKdsPopoverArrowElement;
  private cleanupAutoUpdate: () => void;

  @Listen('click', { target: 'window', capture: true })
  handleClick(event) {
    if (!this.closeOnClickOutsidePopover) {
      return;
    }
    if (!isNullOrUndefined(this.contentRef) && !this.contentRef.contains(event.target)) {
      this.hidePopover();
    }
  }

  @Listen('scroll', { target: 'window', capture: true })
  handleScroll(event) {
    if (!this.closeOnScrollOutsidePopover) {
      return;
    }
    if (!isNullOrUndefined(this.contentRef) && !this.contentRef.contains(event.target)) {
      this.hidePopover();
    }
  }

  /** Removes popover if it is opened. */
  @Method()
  async removePopOver() {
    this.hidePopover();
  }

  private mapEnumsToTypes = (placement: Placement,
    alignment: CaretAlignment): Side | AlignedPlacement => {
    if (alignment === CaretAlignment.left || alignment === CaretAlignment.top) {
      return `${placement}-start`;
    } else if (alignment === CaretAlignment.bottom || alignment === CaretAlignment.right) {
      return `${placement}-end`;
    } else {
      return placement;
    }
  };

  private updatePosition = () => {
    this.cleanupAutoUpdate = autoUpdate(this.triggerRef, this.contentRef, () => {
      computePosition(this.triggerRef, this.contentRef, {
        placement: this.mapEnumsToTypes(this.placement, this.alignment),
        strategy: 'absolute',
        middleware: [
          offset(12),
          flip(),
          arrow({
            element: this.arrowRef
          })
        ]
      }).then(({
        x,
        y,
        placement,
        middlewareData
      }) => {
        const [side, arrow] = placement.split('-');
        Object.assign(this.contentRef.style, {
          left: `${x}px`,
          top: `${y}px`
        });
        const staticSide = {
          top: 'bottom',
          right: 'left',
          bottom: 'top',
          left: 'right'
        }[side];
        const rotate = {
          top: 45,
          right: 135,
          bottom: 225,
          left: 315
        }[side];

        const { x: arrowX, y: arrowY } = middlewareData.arrow;
        const { left, top } = this.calculateArrowPosition(arrow, arrowX, arrowY);
        Object.assign(this.arrowRef.style, {
          left: arrowX != null ? `${left}px` : '',
          top: arrowY != null ? `${top}px` : '',
          right: '',
          bottom: '',
          [staticSide]: '-6px',
          transform: `rotate(${rotate}deg)`
        });
      });
    });
  };

  /**
   * This is due to popover arrow need to left or right placement with top and bottom alignment
   * When trigger-context is very large, popover need to be aligned at the edge
   * When the trigger-context is large, it allows 15 px from width and 25 px from height
   * When at the edge for very small trigger, arrow should move 2px from the edge as adjustment
   **/
  private calculateArrowPosition = (arrow: string,
    arrowX: number | null,
    arrowY: number | null): { left: number, top: number } => {
    let leftArrow: number;
    let topArrow: number;

    const { width: contentWidth, height: contentHeight } = this.contentRef.getBoundingClientRect();
    const { width: triggerWidth, height: triggerHeight } = this.triggerRef.getBoundingClientRect();
    const isStart = arrow === 'start';
    if ((arrow === 'start' || arrow === 'end') && (triggerWidth > 25 && triggerHeight > 25)) {
      leftArrow = isStart ? 15 : contentWidth - 25;
      topArrow = isStart ? 15 : contentHeight - 25;
    } else {
      const adjustment = isStart ? 2 : -2;
      leftArrow = arrowX + adjustment ?? 0;
      topArrow = arrowY + adjustment ?? 0;
    }
    return { left: leftArrow, top: topArrow };
  };


  private readonly showPopover = () => {
    const isAlreadyShown = this.contentRef.style.display === 'block';
    this.contentRef.style.display = 'block';
    if (!isAlreadyShown) {
      this.contentRef.querySelector('.kds-popover-body').scrollTop = 0;
    }
    this.updatePosition();
  };

  private hidePopover = () => {
    this.contentRef.style.display = '';
    this.cleanupAutoUpdate && this.cleanupAutoUpdate(); // this make sure we don't run into infinity loop
  };

  componentDidLoad() {
    this.contentRef = this.hostEle.querySelector('kds-popover-content');
    if (this.contentRef) {
      this.contentRef.style.maxHeight = (PopoverDim[this.size] || PopoverDim.small).height;
      this.contentRef.style.maxWidth = (PopoverDim[this.size] || PopoverDim.small).width;
      this.contentRef.style.zIndex = this.zIndex;

      this.arrowRef = document.createElement('kds-popover-arrow');
      this.triggerRef.addEventListener('click', this.showPopover);
      this.listenIntersectionObserver(this.triggerRef);

      this.contentRef.appendChild(this.arrowRef);
      this.contentRef.appendChild(this.getDismissBtn());
      this.appendOverlayChild(this.contentRef, this.appendTo);
    }
  }

  disconnectedCallback() {
    this.triggerRef?.remove();
  }

  private readonly listenIntersectionObserver = (target: HTMLElement) => {
    const observer = new IntersectionObserver((entries, _observer) => {
      entries.forEach((entry) => {
        if (!entry.isIntersecting) {
          this.hidePopover();
        }
      });
    }, {
      root: null, // Use the viewport as the container
      rootMargin: '0px',
      threshold: 0.5 // Trigger when 50% of the target is visible
    });
    observer.observe(target);
  };

  private readonly appendOverlayChild = (element: any, target: any) => {
    if (!isNullOrUndefined(target)) {
      if (target === 'body') {
        document.body.appendChild(element);
      } else {
        target.appendChild(element);
      }
    }
  };

  private getDismissBtn = () => {
    const dismissBtn = document.createElement('kds-popover-dismiss-btn');
    dismissBtn.addEventListener('click', (event) => {
      event.stopPropagation();
      event.preventDefault();
      this.hidePopover();
    });

    dismissBtn.addEventListener('keyup', (e: any) => {
      if (e.keyCode === 13) {
        this.hidePopover();
      }
    });
    return dismissBtn;
  };

  render() {
    return (
      <Host class='kds-popover'>
        <kds-popover-wrapper id={this.wrapperId}
          ref={(el) => this.triggerRef = el}>
          <slot />
        </kds-popover-wrapper>
      </Host>
    );
  }
}
